1615   ULO.Heart = getLoopConvergenceHeart(L);
1616   ULO.SCEVExpansionBudget = UP.SCEVExpansionBudget;
1617   ULO.RuntimeUnrollMultiExit = UP.RuntimeUnrollMultiExit;
1618   ULO.AddAdditionalAccumulators = UP.AddAdditionalAccumulators;
1619   LoopUnrollResult UnrollResult = UnrollLoop(
1620       L, ULO, LI, &SE, &DT, &AC, &TTI, &ORE, PreserveLCSSA, &RemainderLoop, AA);
1621   if (UnrollResult == LoopUnrollResult::Unmodified)
1622     return LoopUnrollResult::Unmodified;
1623 
1624   if (RemainderLoop) {
1625     std::optional<MDNode *> RemainderLoopID =
1626         makeFollowupLoopID(OrigLoopID, {LLVMLoopUnrollFollowupAll,
1627                                         LLVMLoopUnrollFollowupRemainder});
1628     if (RemainderLoopID)
1629       RemainderLoop->setLoopID(*RemainderLoopID);
1630   }
1631 
1632   if (UnrollResult != LoopUnrollResult::FullyUnrolled) {
1633     std::optional<MDNode *> NewLoopID =
1634         makeFollowupLoopID(OrigLoopID, {LLVMLoopUnrollFollowupAll,
1635                                         LLVMLoopUnrollFollowupUnrolled});
1636     if (NewLoopID) {
1637       L->setLoopID(*NewLoopID);
1638 
1639       // Do not setLoopAlreadyUnrolled if loop attributes have been specified
1640       // explicitly.
1641       return UnrollResult;
1642     }
1643   }
1644 
1645   // If loop has an unroll count pragma or unrolled by explicitly set count
1646   // mark loop as unrolled to prevent unrolling beyond that requested.
1647   if (UnrollResult != LoopUnrollResult::FullyUnrolled && IsCountSetExplicitly)
1648     L->setLoopAlreadyUnrolled();
1649 
1650   return UnrollResult;
1651 }
